python3 ~/.openclaw/skills/calendar/calendar_data.py show --offset 0 --limit 100 | python3 -c "
import sys, json
data = json.load(sys.stdin)
if isinstance(data, list):
    events = data
elif isinstance(data, dict):
    events = data.get('events', data.get('items', [data]))
for e in events:
    if isinstance(e, dict):
        print(json.dumps({k: e.get(k,'') for k in ['event_id','title','description','start_datetime','attendees']}, default=str))
"

